import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.security.KeyStore
import javax.crypto.Cipher
import javax.crypto.KeyGenerator
import javax.crypto.SecretKey

class LoginActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var passwordEditText: EditText
    private lateinit var loginButton: Button
    private lateinit var biometricButton: Button

    private val KEY_NAME = "BiometricAuthKey"
    private val PREFS_NAME = "BiometricAuthPrefs"
    private val KEY_AUTH_TOKEN = "auth_token"
    private val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
    private val CORRECT_PASSWORD = "SecurePassword123"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        passwordEditText = findViewById(R.id.passwordEditText)
        loginButton = findViewById(R.id.loginButton)
        biometricButton = findViewById(R.id.biometricButton)

        if (isAuthenticated()) {
            navigateToMainActivity()
            return
        }

        setupBiometricAuthentication()
        setupPasswordAuthentication()

        if (isBiometricEnabled() && canAuthenticateWithBiometrics()) {
            biometricButton.isEnabled = true
            showBiometricPrompt()
        } else {
            biometricButton.isEnabled = false
        }
    }

    private fun setupBiometricAuthentication() {
        val executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) {
                        Toast.makeText(
                            this@LoginActivity,
                            "Authentication cancelled. Please use password.",
                            Toast.LENGTH_SHORT
                        ).show()
                    } else if (errorCode == BiometricPrompt.ERROR_LOCKOUT ||
                        errorCode == BiometricPrompt.ERROR_LOCKOUT_PERMANENT) {
                        Toast.makeText(
                            this@LoginActivity,
                            "Too many attempts. Please use password.",
                            Toast.LENGTH_LONG
                        ).show()
                        biometricButton.isEnabled = false
                    } else {
                        Toast.makeText(
                            this@LoginActivity,
                            "Authentication error: $errString",
                            Toast.LENGTH_SHORT
                        ).show()
                    }
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    
                    if (result.cryptoObject != null) {
                        saveAuthenticationState()
                        Toast.makeText(
                            this@LoginActivity,
                            "Biometric authentication successful!",
                            Toast.LENGTH_SHORT
                        ).show()
                        navigateToMainActivity()
                    } else {
                        Toast.makeText(
                            this@LoginActivity,
                            "Authentication failed. Please try again.",
                            Toast.LENGTH_SHORT
                        ).show()
                    }
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        this@LoginActivity,
                        "Biometric not recognized. Try again or use password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Authentication")
            .setSubtitle("Log in using your biometric credential")
            .setDescription("Place your finger on the sensor to authenticate")
            .setNegativeButtonText("Use Password")
            .setConfirmationRequired(true)
            .build()

        biometricButton.setOnClickListener {
            showBiometricPrompt()
        }
    }

    private fun setupPasswordAuthentication() {
        loginButton.setOnClickListener {
            val password = passwordEditText.text.toString()
            if (validatePassword(password)) {
                saveAuthenticationState()
                enableBiometricForFuture()
                Toast.makeText(this, "Login successful!", Toast.LENGTH_SHORT).show()
                navigateToMainActivity()
            } else {
                Toast.makeText(this, "Invalid password. Please try again.", Toast.LENGTH_SHORT).show()
                passwordEditText.text.clear()
            }
        }
    }

    private fun showBiometricPrompt() {
        if (canAuthenticateWithBiometrics()) {
            try {
                val cipher = getCipher()
                val secretKey = getOrCreateSecretKey()
                cipher.init(Cipher.ENCRYPT_MODE, secretKey)
                val cryptoObject = BiometricPrompt.CryptoObject(cipher)
                biometricPrompt.authenticate(promptInfo, cryptoObject)
            } catch (e: Exception) {
                Toast.makeText(
                    this,
                    "Biometric initialization failed. Please use password.",
                    Toast.LENGTH_SHORT
                ).show()
                e.printStackTrace()
            }
        } else {
            Toast.makeText(
                this,
                "Biometric authentication not available. Please use password.",
                Toast.LENGTH_SHORT
            ).show()
        }
    }

    private fun canAuthenticateWithBiometrics(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)) {
            BiometricManager.BIOMETRIC_SUCCESS -> true
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                Toast.makeText(this, "No biometric hardware available", Toast.LENGTH_SHORT).show()
                false
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                Toast.makeText(this, "Biometric hardware unavailable", Toast.LENGTH_SHORT).show()
                false
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                Toast.makeText(this, "No biometric credentials enrolled", Toast.LENGTH_SHORT).show()
                false
            }
            else -> false
        }
    }

    private fun getOrCreateSecretKey(): SecretKey {
        val keyStore = KeyStore.getInstance("AndroidKeyStore")
        keyStore.load(null)

        keyStore.getKey(KEY_NAME, null)?.let {
            return it as SecretKey
        }

        val keyGenerator = KeyGenerator.getInstance(
            KeyProperties.KEY_ALGORITHM_AES,
            "AndroidKeyStore"
        )

        val keyGenParameterSpec = KeyGenParameterSpec.Builder(
            KEY_NAME,
            KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
        )
            .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
            .setUserAuthenticationRequired(true)
            .setInvalidatedByBiometricEnrollment(true)
            .build()

        keyGenerator.init(keyGenParameterSpec)
        return keyGenerator.generateKey()
    }

    private fun getCipher(): Cipher {
        return Cipher.getInstance(
            KeyProperties.KEY_ALGORITHM_AES + "/"
                    + KeyProperties.BLOCK_MODE_CBC + "/"
                    + KeyProperties.ENCRYPTION_PADDING_PKCS7
        )
    }

    private fun validatePassword(password: String): Boolean {
        return password == CORRECT_PASSWORD
    }

    private fun saveAuthenticationState() {
        val authToken = generateSecureToken()
        sharedPreferences.edit().apply {
            putString(KEY_AUTH_TOKEN, authToken)
            putLong("auth_timestamp", System.currentTimeMillis())
            apply()
        }
    }

    private fun enableBiometricForFuture() {
        if (canAuthenticateWithBiometrics()) {
            sharedPreferences.edit().apply {
                putBoolean(KEY_BIOMETRIC_ENABLED, true)
                apply()
            }
        }
    }

    private fun isAuthenticated(): Boolean {
        val authToken = sharedPreferences.getString(KEY_AUTH_TOKEN, null)
        val authTimestamp = sharedPreferences.getLong("auth_timestamp", 0)
        val currentTime = System.currentTimeMillis()
        val sessionTimeout = 24 * 60 * 60 * 1000 // 24 hours

        return authToken != null && (currentTime - authTimestamp) < sessionTimeout
    }

    private fun isBiometricEnabled(): Boolean {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false)
    }

    private fun generateSecureToken(): String {
        return java.util.UUID.randomUUID().toString()
    }

    private fun navigateToMainActivity() {
        val intent = Intent(this, MainActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}

class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var logoutButton: Button

    private val PREFS_NAME = "BiometricAuthPrefs"
    private val KEY_AUTH_TOKEN = "auth_token"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        logoutButton = findViewById(R.id.logoutButton)
        logoutButton.setOnClickListener {
            logout()
        }
    }

    private fun logout() {
        sharedPreferences.edit().apply {
            remove(KEY_AUTH_TOKEN)
            remove("auth_timestamp")
            apply()
        }

        val intent = Intent(this, LoginActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
